#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
  float weight;
  long assign;
  float cost;
} Point;

inline float d_dist(int p1, int p2, int num, int dim, __global float *coord_d)
{
  float retval = 0.0f;
  for(int i = 0; i < dim; i++){
    float tmp = coord_d[(i*num)+p1] - coord_d[(i*num)+p2];
    retval += tmp * tmp;
  }
  return retval;
}

__kernel void kernel_compute_cost(
  const int num,
  const int dim,
  const long x,
  __global Point *p,
  const int K,
  const int stride,
  __global float *coord_d,
  __global float *work_mem_d,
  __global int *center_table_d,
  __global char *switch_membership_d)
{
  const int bid  = get_group_id(0) + get_num_groups(0) * get_group_id(1);
  const int tid = get_local_size(0) * bid + get_local_id(0);

  if(tid < num)
  {
    __global float *lower = &work_mem_d[tid*stride];

    float x_cost = d_dist(tid, x, num, dim, coord_d) * p[tid].weight;

    if ( x_cost < p[tid].cost )
    {
      switch_membership_d[tid] = 1;
      lower[K] += x_cost - p[tid].cost;
    }
    else
    {
      lower[center_table_d[p[tid].assign]] += p[tid].cost - x_cost;
    }
  }
}
